#include <iostream>
#include <vector>
#include <algorithm>

bool bubbleSort(std::vector<int>& nums) {
    int flag = 0;
    for (int i = 0; i < nums.size(); i++) {
        for (int j = 0; j < nums.size() - 1; j++) {
            if (nums[j] > nums[j + 1]) {
                std::swap(nums[j], nums[j + 1]);
                flag = 1;
            }
        }
        if (flag == 0) break;
    }
    return true;
}

int main() {
    std::vector<int> nums = {5, 3, 8, 1, 4};
    if (bubbleSort(nums)) {
        std::cout << "Sorted in ascending order" << std::endl;
    } else {
        std::cout << "Not sorted in ascending order" << std::endl;
    }
    return 0;
}

